    @ec_minimo decimal(4, 2) = NULL,
    @ec_maximo decimal(4, 2) = NULL,
    @instrucciones_especiales nvarchar(max) = NULL,
    @activa bit
AS

BEGIN SET NOCOUNT ON;
BEGIN TRANSACTION DELETE FROM [dbo].[Categorias] WHERE categoria_id = @categoria_id
SELECT @categoria_id AS CategoriaId COMMIT TRANSACTION END

BEGIN SET NOCOUNT ON;
BEGIN TRANSACTION DELETE FROM [dbo].[Productos] WHERE producto_id = @producto_id
SELECT @producto_id AS producto_id COMMIT TRANSACTION END

BEGIN SET NOCOUNT ON;
BEGIN TRANSACTION DELETE FROM [dbo].[Tipos_Cultivo] WHERE tipo_cultivo_id = @tipo_cultivo_id
SELECT @tipo_cultivo_id AS TipoCultivoId COMMIT TRANSACTION END

BEGIN SET NOCOUNT ON;
BEGIN TRANSACTION DELETE FROM [dbo].[Unidades_Medida] WHERE unidad_id = @unidad_id
SELECT @unidad_id AS unidad_id COMMIT TRANSACTION END

BEGIN SET NOCOUNT ON;
BEGIN TRANSACTION DELETE FROM [dbo].[Variedades] WHERE variedad_id = @variedad_id
SELECT @variedad_id AS VariedadId COMMIT TRANSACTION END

BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        BEGIN TRAN;

        -- Validar ciclo
        DECLARE
            @producto_id INT,
            @cantidad_plantas INT,
            @estado_ciclo_actual_id INT,
            @codigo_producto NVARCHAR(30),
            @dias_caducidad INT;

        SELECT
            @producto_id = c.producto_id,
            @cantidad_plantas = c.cantidad_plantas,
            @estado_ciclo_actual_id = c.estado_ciclo_id
        FROM dbo.Ciclos c
        WHERE c.ciclo_id = @ciclo_id;

        IF @producto_id IS NULL
            THROW 51001, 'Ciclo no existe.', 1;

        -- No permitir cosechar dos veces (1 inventario por ciclo)
        IF EXISTS (SELECT 1 FROM dbo.Inventario_Actual WHERE ciclo_origen_id = @ciclo_id)
            THROW 51002, 'Este ciclo ya fue cosechado y ya generó inventario.', 1;

        -- Estado COSECHADO
        DECLARE @estado_cosechado_id INT =
            (SELECT estado_ciclo_id FROM dbo.Estados_Ciclo WHERE codigo = N'COSECHADO' AND activo = 1);

        IF @estado_cosechado_id IS NULL
            THROW 51003, 'No existe el estado COSECHADO en Estados_Ciclo.', 1;

        -- Permitir cosechar aunque esté activo, pero no si ya está cosechado/cancelado
        IF @estado_ciclo_actual_id = @estado_cosechado_id
            THROW 51004, 'El ciclo ya está en estado COSECHADO.', 1;

        -- Calidad
        DECLARE @estado_calidad_id INT =
            (SELECT estado_calidad_id FROM dbo.Estados_Calidad WHERE codigo = @estado_calidad_codigo AND activo = 1);

        IF @estado_calidad_id IS NULL
            THROW 51005, 'Estado de calidad inválido.', 1;

        -- Producto: código y días de caducidad para lote y fecha_caducidad
        SELECT
            @codigo_producto = p.codigo,
            @dias_caducidad = p.dias_caducidad
        FROM dbo.Productos p
        WHERE p.producto_id = @producto_id AND p.activo = 1;

        IF @codigo_producto IS NULL
            THROW 51006, 'Producto inválido o inactivo.', 1;

        -- Generar lote: CODIGO-PRODUCTO-MMDDYY (ej: LEC-001-012926)
        DECLARE @hoy DATE = CAST(SYSDATETIME() AS DATE);
        DECLARE @lote NVARCHAR(100) =
            @codigo_producto + N'-' + FORMAT(@hoy, 'MMddyy');

        -- 1) Cerrar ciclo (libera capacidad al dejar de ser activo)
        UPDATE dbo.Ciclos
        SET estado_ciclo_id = @estado_cosechado_id,
            fecha_cosecha_real = @hoy
        WHERE ciclo_id = @ciclo_id;

        -- 2) Crear inventario vendible con lo plantado
        INSERT INTO dbo.Inventario_Actual
        (
            producto_id, ubicacion_id, estado_calidad_id,
            lote, cantidad_disponible,
            fecha_entrada, fecha_caducidad,
            ciclo_origen_id, notas
        )
        VALUES
        (
            @producto_id, @ubicacion_id, @estado_calidad_id,
            @lote, @cantidad_plantas,
            @hoy, DATEADD(DAY, @dias_caducidad, @hoy),
            @ciclo_id, @motivo
        );

        DECLARE @inventario_id INT = SCOPE_IDENTITY();

        -- 3) Registrar movimiento de inventario tipo ENTRADA (cosecha)
        DECLARE @tipo_entrada_id INT =
            (SELECT tipo_movimiento_id FROM dbo.Tipos_Movimiento WHERE codigo = N'ENTRADA' AND activo = 1);

        IF @tipo_entrada_id IS NULL
            THROW 51007, 'No existe tipo movimiento ENTRADA.', 1;

        INSERT INTO dbo.Movimientos_Inventario
        (
            inventario_id, producto_id, tipo_movimiento_id,
            ubicacion_destino_id, cantidad,
            motivo, usuario_id
        )
        VALUES
        (
            @inventario_id, @producto_id, @tipo_entrada_id,
            @ubicacion_id, @cantidad_plantas,
            ISNULL(@motivo, N'Cosecha de ciclo ' + CAST(@ciclo_id AS NVARCHAR(20))),
            @usuario_id
        );

        COMMIT;

        SELECT @inventario_id AS inventario_id_creado, @lote AS lote_generado;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        THROW;
    END CATCH
END

CREATE   PROCEDURE [dbo].[sp_Ciclo_Cosechar]
    @ciclo_id INT,
    @ubicacion_id INT,          -- la elige el usuario
    @estado_calidad_codigo NVARCHAR(30), -- OPTIMO/REGULAR/etc
    @usuario_id INT,            -- empleado que hace la acción
    @motivo NVARCHAR(MAX) = NULL
AS

BEGIN
    SET NOCOUNT ON;

    IF @cantidad_plantas IS NULL OR @cantidad_plantas <= 0
        THROW 50001, 'La cantidad_plantas debe ser mayor a 0.', 1;

    DECLARE @estado_ciclo_id INT =
        (SELECT estado_ciclo_id FROM dbo.Estados_Ciclo WHERE codigo = @estado_ciclo_codigo AND activo = 1);

    IF @estado_ciclo_id IS NULL
        THROW 50002, 'Estado de ciclo inválido.', 1;

    DECLARE @capacidad INT = (SELECT capacidad_maxima_plantas FROM dbo.Torres WHERE torre_id = @torre_id AND activo = 1);
    IF @capacidad IS NULL
        THROW 50003, 'Torre inválida o inactiva.', 1;

    -- Ocupado actual: suma de ciclos activos
    DECLARE @ocupado INT =
    (
        SELECT ISNULL(SUM(c.cantidad_plantas), 0)
        FROM dbo.Ciclos c
        JOIN dbo.Estados_Ciclo ec ON ec.estado_ciclo_id = c.estado_ciclo_id
        WHERE c.torre_id = @torre_id
          AND ec.es_activo = 1
    );

    IF (@ocupado + @cantidad_plantas) > @capacidad
        THROW 50004, 'No se puede plantar: excede la capacidad de la torre.', 1;

    INSERT INTO dbo.Ciclos
    (
        producto_id, variedad_id, torre_id, estado_ciclo_id,
        fecha_siembra, fecha_cosecha_estimada,
        cantidad_plantas, responsable_id,
        lote_semilla, notas
    )
    VALUES
    (
        @producto_id, @variedad_id, @torre_id, @estado_ciclo_id,
        @fecha_siembra, @fecha_cosecha_estimada,
        @cantidad_plantas, @responsable_id,
        @lote_semilla, @notas
    );

    SELECT SCOPE_IDENTITY() AS ciclo_id_creado;
END

CREATE   PROCEDURE [dbo].[sp_Ciclo_RegistrarSiembra]
    @producto_id INT,
    @variedad_id INT,
    @torre_id INT,
    @estado_ciclo_codigo NVARCHAR(30), -- SIEMBRA, por ejemplo
    @fecha_siembra DATE,
    @fecha_cosecha_estimada DATE,
    @cantidad_plantas INT,
    @responsable_id INT,
    @lote_semilla NVARCHAR(100) = NULL,
    @notas NVARCHAR(MAX) = NULL
AS

BEGIN
    SET NOCOUNT ON;

    IF @cantidad IS NULL OR @cantidad <= 0
        THROW 53001, 'La cantidad debe ser mayor a 0.', 1;

    IF @precio_unitario IS NULL OR @precio_unitario < 0
        THROW 53002, 'El precio_unitario no puede ser negativo.', 1;

    IF @descuento_unitario IS NULL OR @descuento_unitario < 0
        THROW 53003, 'El descuento_unitario no puede ser negativo.', 1;

    IF @descuento_unitario > @precio_unitario
        THROW 53004, 'El descuento_unitario no puede ser mayor al precio_unitario.', 1;

    BEGIN TRY
        BEGIN TRAN;

        -- Validar venta existe
        IF NOT EXISTS (SELECT 1 FROM dbo.Ventas WHERE venta_id = @venta_id)
            THROW 53005, 'La venta no existe.', 1;

        -- Tomar inventario y bloquear fila para evitar doble descuento concurrente
        DECLARE @producto_id INT, @ubicacion_id INT, @stock INT;

        SELECT
            @producto_id = ia.producto_id,
            @ubicacion_id = ia.ubicacion_id,
            @stock = ia.cantidad_disponible
        FROM dbo.Inventario_Actual ia WITH (UPDLOCK, ROWLOCK)
        WHERE ia.inventario_id = @inventario_id;

        IF @producto_id IS NULL
            THROW 53006, 'Inventario no existe.', 1;

        IF @stock < @cantidad
            THROW 53007, 'Stock insuficiente para completar la salida.', 1;

        -- Descontar inventario
        UPDATE dbo.Inventario_Actual
        SET cantidad_disponible = cantidad_disponible - @cantidad
        WHERE inventario_id = @inventario_id;

        -- Insertar detalle
        INSERT INTO dbo.Detalle_Ventas
        (
            venta_id, inventario_id, producto_id,
            cantidad, precio_unitario, descuento_unitario
        )
        VALUES
        (
            @venta_id, @inventario_id, @producto_id,
            @cantidad, @precio_unitario, @descuento_unitario
        );

        DECLARE @detalle_id INT = SCOPE_IDENTITY();

        -- Movimiento SALIDA
        DECLARE @tipo_salida_id INT =
            (SELECT tipo_movimiento_id FROM dbo.Tipos_Movimiento WHERE codigo = N'SALIDA' AND activo = 1);

        IF @tipo_salida_id IS NULL
            THROW 53008, 'No existe tipo movimiento SALIDA.', 1;

        INSERT INTO dbo.Movimientos_Inventario
        (
            inventario_id, producto_id, tipo_movimiento_id,
            ubicacion_origen_id, cantidad,
            motivo, usuario_id
        )
        VALUES
        (
            @inventario_id, @producto_id, @tipo_salida_id,
            @ubicacion_id, @cantidad,
            ISNULL(@motivo, N'Salida por venta ' + CAST(@venta_id AS NVARCHAR(20))),
            @usuario_id
        );

        -- Recalcular totales del encabezado (simple)
        DECLARE @subtotal DECIMAL(10,2) =
        (
            SELECT ISNULL(SUM(CAST(subtotal AS DECIMAL(10,2))), 0.00)
            FROM dbo.Detalle_Ventas
            WHERE venta_id = @venta_id
        );

        -- IVA desde config si existe, si no 13
        DECLARE @iva_porcentaje DECIMAL(10,2) = 13.00;
        SELECT @iva_porcentaje = TRY_CAST(valor AS DECIMAL(10,2))
        FROM dbo.Config_Sistema
        WHERE clave = N'iva_porcentaje' AND activo = 1;

        DECLARE @iva_monto DECIMAL(10,2) = ROUND(@subtotal * (@iva_porcentaje/100.0), 2);
        DECLARE @total DECIMAL(10,2) = @subtotal + @iva_monto;

        UPDATE dbo.Ventas
        SET subtotal = @subtotal,
            iva_monto = @iva_monto,
            total = @total
        WHERE venta_id = @venta_id;

        COMMIT;

        SELECT
            @detalle_id AS detalle_id_creado,
            @subtotal AS venta_subtotal,
            @iva_monto AS venta_iva,
            @total AS venta_total;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK;
        THROW;
    END CATCH
END

CREATE   PROCEDURE [dbo].[sp_Venta_AgregarDetalle_DescontarInventario]
    @venta_id INT,
    @inventario_id INT,
    @cantidad INT,
    @precio_unitario DECIMAL(10,2),
    @descuento_unitario DECIMAL(10,2) = 0.00,
    @usuario_id INT,
    @motivo NVARCHAR(MAX) = NULL
AS

BEGIN
    SET NOCOUNT ON;

    DECLARE @estado_venta_id INT = (SELECT estado_venta_id FROM dbo.Estados_Venta WHERE codigo=@estado_venta_codigo AND activo=1);
    IF @estado_venta_id IS NULL THROW 52001, 'Estado de venta inválido.', 1;

    DECLARE @estado_pago_id INT = (SELECT estado_pago_id FROM dbo.Estados_Pago WHERE codigo=@estado_pago_codigo AND activo=1);
    IF @estado_pago_id IS NULL THROW 52002, 'Estado de pago inválido.', 1;

    DECLARE @tipo_entrega_id INT = (SELECT tipo_entrega_id FROM dbo.Tipos_Entrega WHERE codigo=@tipo_entrega_codigo AND activo=1);
    IF @tipo_entrega_id IS NULL THROW 52003, 'Tipo de entrega inválido.', 1;

    DECLARE @metodo_pago_id INT = NULL;
    IF @metodo_pago_codigo IS NOT NULL
    BEGIN
        SET @metodo_pago_id = (SELECT metodo_pago_id FROM dbo.Metodos_Pago WHERE codigo=@metodo_pago_codigo AND activo=1);
        IF @metodo_pago_id IS NULL THROW 52004, 'Método de pago inválido.', 1;
    END

    INSERT INTO dbo.Ventas
    (
        cliente_id, direccion_entrega_id, vendedor_id,
        estado_venta_id, estado_pago_id, metodo_pago_id,
        tipo_entrega_id, notas
    )
    VALUES
    (
        @cliente_id, @direccion_entrega_id, @vendedor_id,
        @estado_venta_id, @estado_pago_id, @metodo_pago_id,
        @tipo_entrega_id, @notas
    );

    SELECT SCOPE_IDENTITY() AS venta_id_creada;
END

CREATE   PROCEDURE [dbo].[sp_Venta_Crear]
    @cliente_id INT,
    @direccion_entrega_id INT,
    @vendedor_id INT,
    @estado_venta_codigo NVARCHAR(30) = N'PENDIENTE',
    @estado_pago_codigo NVARCHAR(30) = N'PENDIENTE',
    @metodo_pago_codigo NVARCHAR(30) = NULL,
    @tipo_entrega_codigo NVARCHAR(30) = N'RECOGE',
    @notas NVARCHAR(MAX) = NULL
AS

BEGIN
    SET NOCOUNT ON;

    UPDATE notif.Alerta
    SET
        estado = 'ACEPTADA',
        fecha_aceptada = SYSDATETIME(),
        usuario_acepta_id = @empleado_id
    WHERE alerta_id = @alerta_id
      AND estado = 'ACTIVA';

    /* Resultado explícito para API */
    SELECT
        @@ROWCOUNT AS filas_afectadas,
        @alerta_id AS alerta_id,
        @empleado_id AS empleado_id;
END

BEGIN
    SET NOCOUNT ON;

    SELECT COUNT(*) AS badge_count
    FROM notif.Alerta
    WHERE estado = 'ACTIVA';
END

BEGIN SET NOCOUNT ON;
DECLARE @stock_minimo_general INT;
SELECT TOP (1) @stock_minimo_general = TRY_CONVERT(INT, cs.valor) FROM dbo.Config_Sistema cs WHERE cs.clave = N'stock_minimo_general' AND cs.activo = 1 ORDER BY cs.config_id DESC;
IF @stock_minimo_general IS NULL SET @stock_minimo_general = 15;
BEGIN TRY SET TRANSACTION ISOLATION LEVEL SERIALIZABLE; BEGIN TRAN;
/* Tabla temporal reutilizable */ IF OBJECT_ID('tempdb..#Stock') IS NOT NULL DROP TABLE #Stock;
CREATE TABLE #Stock ( producto_id INT NOT NULL PRIMARY KEY, nombre_producto NVARCHAR(400) NOT NULL, disponible_total INT NOT NULL, minimo INT NOT NULL );
INSERT INTO #Stock (producto_id, nombre_producto, disponible_total, minimo) SELECT p.producto_id, p.nombre_producto, ISNULL(SUM(ia.cantidad_disponible), 0) AS disponible_total, COALESCE(p.stock_minimo, @stock_minimo_general) AS minimo FROM dbo.Productos p LEFT JOIN dbo.Inventario_Actual ia ON ia.producto_id = p.producto_id GROUP BY p.producto_id, p.nombre_producto, p.stock_minimo;
/* 1) REARMAR: si se recuperó (> mínimo), marcar rearmado_en en aceptadas bloqueantes */ UPDATE a SET a.rearmado_en = SYSDATETIME() FROM notif.Alerta a JOIN #Stock s ON s.producto_id = a.producto_id WHERE a.tipo_alerta = 'STOCK_BAJO' AND a.estado = 'ACEPTADA' AND a.rearmado_en IS NULL AND s.disponible_total > s.minimo;
/* 2) GENERAR: si está bajo y NO hay ACTIVA y NO hay ACEPTADA bloqueante */ INSERT INTO notif.Alerta ( tipo_alerta, producto_id, estado, mensaje, snapshot_disponible, snapshot_minimo ) SELECT 'STOCK_BAJO', s.producto_id, 'ACTIVA', CONCAT(N'Stock bajo en ', s.nombre_producto, N' disponible ', s.disponible_total), s.disponible_total, s.minimo FROM #Stock s WHERE s.disponible_total <= s.minimo AND NOT EXISTS ( SELECT 1 FROM notif.Alerta a WITH (UPDLOCK, HOLDLOCK) WHERE a.tipo_alerta = 'STOCK_BAJO' AND a.producto_id = s.producto_id AND a.estado = 'ACTIVA' ) AND NOT EXISTS ( SELECT 1 FROM notif.Alerta a2 WHERE a2.tipo_alerta = 'STOCK_BAJO' AND a2.producto_id = s.producto_id AND a2.estado = 'ACEPTADA' AND a2.rearmado_en IS NULL );
COMMIT;
/* Dataset 1: badge_count (solo ACTIVA) */ SELECT COUNT(*) AS badge_count FROM notif.Alerta WHERE estado = 'ACTIVA';
/* Dataset 2: lista de alertas ACTIVAS */ SELECT a.alerta_id, a.tipo_alerta, a.estado, a.fecha_creacion, a.mensaje, a.producto_id, p.nombre_producto, a.snapshot_disponible, a.snapshot_minimo, disponible_actual = s.disponible_total, minimo_actual = s.minimo FROM notif.Alerta a JOIN dbo.Productos p ON p.producto_id = a.producto_id JOIN #Stock s ON s.producto_id = a.producto_id WHERE a.estado = 'ACTIVA' ORDER BY a.fecha_creacion DESC, a.alerta_id DESC;
END TRY BEGIN CATCH IF @@TRANCOUNT > 0 ROLLBACK; THROW; END CATCH END
